const webhookData = $('Rollup Account Webhook').first().json.body || $('Rollup Account Webhook').first().json;
const targetName = (webhookData.account_name || '').toString().trim().toLowerCase();
if (!targetName) {
  throw new Error('Missing required field: account_name');
}

const rows = $input.all().map(i => i.json).filter(r => {
  const n = (r.account_name || r['account_name '] || '').toString().trim().toLowerCase();
  return n === targetName;
});
if (rows.length === 0) {
  throw new Error(`No RiskData row found for account_name "${webhookData.account_name}"`);
}

function slugify(s) {
  return s.toLowerCase().trim().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');
}

const accountName = (rows[0].account_name || rows[0]['account_name ']).toString().trim();
const accountId = slugify(accountName);

const sorted = [...rows].sort((a, b) => new Date(b.last_updated || 0) - new Date(a.last_updated || 0));
const mostRecent = sorted[0];

let representative = rows[0];
for (const r of rows) {
  const score = parseFloat(r.financial_risk_score) || 0;
  if (score > (parseFloat(representative.financial_risk_score) || 0)) representative = r;
}

const arr = parseFloat(mostRecent.arr) || 0;

function contractTier(a) {
  if (a >= 500000) return 'Strategic';
  if (a >= 200000) return 'Enterprise';
  if (a >= 50000) return 'Growth';
  return 'Starter';
}

const renewalDays = parseInt(mostRecent.renewal_horizon_days, 10);
const renewalDate = !isNaN(renewalDays)
  ? new Date(Date.now() + renewalDays * 86400000).toISOString().slice(0, 10)
  : null;

const sentimentRank = { critical: 4, frustrated: 3, concerned: 2, neutral: 1, satisfied: 0 };
let worstSentiment = 'neutral';
let worstRank = -1;
for (const r of rows) {
  const s = (r.sentiment || '').toLowerCase();
  const rank = sentimentRank[s] ?? -1;
  if (rank > worstRank) { worstRank = rank; worstSentiment = s || 'neutral'; }
}

const escalationCount = rows.filter(r => String(r.escalation_flag).toLowerCase() === 'true').length;

const churnRiskScore = Math.min(1, (parseFloat(representative.financial_risk_score) || 0) / 100);
let churnRiskTier = 'low';
if (churnRiskScore > 0.8) churnRiskTier = 'critical';
else if (churnRiskScore > 0.6) churnRiskTier = 'high';
else if (churnRiskScore > 0.4) churnRiskTier = 'medium';

const revenueAtRisk = Math.round(arr * churnRiskScore);

let jiraTicketKey = null;
for (const r of rows) {
  if (r.jira_ticket_key) { jiraTicketKey = r.jira_ticket_key; break; }
}

const issues = rows.map((r, i) => ({
  issue_id: `issue-${accountId}-${i + 1}`,
  description: r.bug_summary || '',
  severity: r.bug_severity || null,
  days_open: parseInt(r.days_issue_open, 10) || null,
  source: r.source_channel || 'manual_form',
  source_ref: null,
  jira_ticket: r.jira_ticket_key || null,
  first_reported: r.last_updated || null,
  last_updated: r.last_updated || null
}));

return [{
  json: {
    account_id: accountId,
    account_name: accountName,
    arr,
    contract_tier: contractTier(arr),
    renewal_date: renewalDate,
    days_to_renewal: !isNaN(renewalDays) ? renewalDays : null,
    cs_owner: mostRecent.cs_owner || null,
    issues_json: JSON.stringify(issues),
    escalation_count: escalationCount,
    sentiment: worstSentiment,
    churn_risk_score: Math.round(churnRiskScore * 100) / 100,
    churn_risk_tier: churnRiskTier,
    revenue_at_risk: revenueAtRisk,
    recommended_action: representative.recommended_action || '',
    jira_ticket_key: jiraTicketKey,
    primary_technical_domain: representative.technical_domain || '',
    top_issue_summary: representative.bug_summary || ''
  }
}];

const agg = $('Aggregate Account').first().json;
const claudeResponse = $input.first().json;
const toolUse = (claudeResponse.content || []).find(b => b.type === 'tool_use');
const executiveSummary = toolUse?.input?.executive_summary || '';

return [{
  json: {
    ...agg,
    executive_summary: executiveSummary,
    last_synced: new Date().toISOString()
  }
}];
